import React from 'react';

import Link from './Link';
import LinkStore from '../stores/LinkStore';

export default function Links() {
  return (
    <div className="links">
      {LinkStore.getAll().map((link, i) => (
        <Link key={i} link={link} />
      ))}
    </div>
  );
}



